import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int bufferSize = 10; // Size of the buffer
        char[] buffer = new char[bufferSize];

        // Copy input into buffer with bounds checking
        for (int i = 0; i < Math.min(input.length(), bufferSize); i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
